18. {
19.     public class CoursesController : BaseController
20.     {
21.         private readonly IWebHostEnvironment _env;
22.         private readonly ILogger<CoursesController> _logger;
23. 
24.         public CoursesController(SchoolContext context, IWebHostEnvironment env, ILogger<CoursesController> logger) : base(context)
25.         {
26.             _env = env;
27.             _logger = logger;
28.         }
29. 
30.         // GET: Courses
31.         public ActionResult Index()
32.         {
33.             var courses = db.Courses.Include(c => c.Department);
34.             return View(courses.ToList());
35.         }
36. 
37.         // GET: Courses/Details/5
38.         public ActionResult Details(int? id)
39.         {
40.             if (id == null)
41.             {
42.                 return new StatusCodeResult((int)HttpStatusCode.BadRequest);
43.             }
44.             Course course = db.Courses.Include(c => c.Department).Where(c => c.CourseID == id).Single();
45.             if (course == null)
46.             {
47.                 return NotFound();
48.             }
49.             return View(course);
50.         }
51. 
52.         // GET: Courses/Create
53.         public ActionResult Create()
54.         {
55.             ViewBag.DepartmentID = new SelectList(db.Departments, "DepartmentID", "Name");
56.             return View(new Course());
57.         }
58. 
59.         // POST: Courses/Create
60.         [HttpPost]
61.         [ValidateAntiForgeryToken]
62.         public ActionResult Create([Bind("CourseID", "Title", "Credits", "DepartmentID", "TeachingMaterialImagePath")] Course course, IFormFile teachingMaterialImage)
63.         {
64.             if (ModelState.IsValid)
65.             {
66.                 if (teachingMaterialImage != null && teachingMaterialImage.Length > 0)
67.                 {
68.                     var allowedExtensions = new[] { ".jpg", ".jpeg", ".png", ".gif", ".bmp" };
69.                     var fileExtension = Path.GetExtension(teachingMaterialImage.FileName).ToLower();
70.                     if (!allowedExtensions.Contains(fileExtension))
71.                     {
72.                         ModelState.AddModelError("teachingMaterialImage", "Please upload a valid image file (jpg, jpeg, png, gif, bmp).");
73.                         ViewBag.DepartmentID = new SelectList(db.Departments, "DepartmentID", "Name", course.DepartmentID);
74.                         return View(course);
75.                     }
76.                     if (teachingMaterialImage.Length > 5 * 1024 * 1024)
77.                     {
78.                         ModelState.AddModelError("teachingMaterialImage", "File size must be less than 5MB.");
79.                         ViewBag.DepartmentID = new SelectList(db.Departments, "DepartmentID", "Name", course.DepartmentID);
80.                         return View(course);
81.                     }
