namespace ContosoUniversity.Tests.Controllers
{
    public class StudentsControllerTests : IDisposable
    {
        private readonly SchoolContext _context;
        private readonly StudentsController _controller;

        public StudentsControllerTests()
        {
            NotificationQueueDrainer.Drain();
            _context = TestDbContextFactory.Create();
            _controller = new StudentsController(_context);
        }

        public void Dispose()
        {
            _controller.Dispose();
            _context.Dispose();
            NotificationQueueDrainer.Drain();
        }

        private Student SeedStudent(string firstName = "John", string lastName = "Doe", DateTime? enrollmentDate = null)
        {
            var student = new Student
            {
                FirstMidName = firstName,
                LastName = lastName,
                EnrollmentDate = enrollmentDate ?? new DateTime(2020, 9, 1)
            };
            _context.Students.Add(student);
            _context.SaveChanges();
            return student;
        }

        private void SeedMultipleStudents()
        {
            _context.Students.AddRange(
                new Student { FirstMidName = "Alice", LastName = "Anderson", EnrollmentDate = new DateTime(2020, 1, 1) },
                new Student { FirstMidName = "Bob", LastName = "Brown", EnrollmentDate = new DateTime(2021, 1, 1) },
                new Student { FirstMidName = "Charlie", LastName = "Clark", EnrollmentDate = new DateTime(2019, 1, 1) }
            );
            _context.SaveChanges();
        }

