        public void Index_DateSort_OrdersByEnrollmentDateAsc()
        {
            SeedMultipleStudents();

            var result = _controller.Index("Date", null, null, null) as ViewResult;
            var model = Assert.IsAssignableFrom<PaginatedList<Student>>(result.Model);

            Assert.Equal("Clark", model[0].LastName);   // 2019
            Assert.Equal("Anderson", model[1].LastName); // 2020
            Assert.Equal("Brown", model[2].LastName);    // 2021
