        public void Index_DateDescSort_OrdersByEnrollmentDateDesc()
        {
            SeedMultipleStudents();

            var result = _controller.Index("date_desc", null, null, null) as ViewResult;
            var model = Assert.IsAssignableFrom<PaginatedList<Student>>(result.Model);

            Assert.Equal("Brown", model[0].LastName);    // 2021
            Assert.Equal("Anderson", model[1].LastName); // 2020
            Assert.Equal("Clark", model[2].LastName);    // 2019
        }

