            SeedMultipleStudents();

            var result = _controller.Index(null, null, "Brown", null) as ViewResult;
            var model = Assert.IsAssignableFrom<PaginatedList<Student>>(result.Model);

            Assert.Single(model);
            Assert.Equal("Brown", model[0].LastName);
        }

        [Fact]
