        {
            SeedMultipleStudents();

            var result = _controller.Index(null, null, "Alice", null) as ViewResult;
            var model = Assert.IsAssignableFrom<PaginatedList<Student>>(result.Model);

            Assert.Single(model);
            Assert.Equal("Anderson", model[0].LastName);
        }

