        public void Index_NullSearch_UsesCurrentFilter()
        {
            SeedMultipleStudents();

            var result = _controller.Index(null, "Brown", null, null) as ViewResult;
            var model = Assert.IsAssignableFrom<PaginatedList<Student>>(result.Model);

            Assert.Single(model);
        }

        [Fact]
