            // Use a temp directory for web root so file operations don't mess up real dirs
            _testWebRoot = Path.Combine(Path.GetTempPath(), "contoso_test_" + Guid.NewGuid().ToString("N"));
            Directory.CreateDirectory(_testWebRoot);
            _mockEnv.Setup(e => e.WebRootPath).Returns(_testWebRoot);
