        {
            // Enqueue some notifications
            var service = new NotificationService();
            for (int i = 0; i < 15; i++)
            {
                service.SendNotification("Test", i.ToString(), EntityOperation.CREATE);
            }

            var result = _controller.GetNotifications();
            var json = result.Value;

            var countProp = json.GetType().GetProperty("count");
            Assert.Equal(10, (int)countProp.GetValue(json));

            service.Dispose();
        }

        [Fact]
        public void GetNotifications_DequeuesNotifications()
        {
            var service = new NotificationService();
            service.SendNotification("Student", "1", EntityOperation.CREATE);
            service.SendNotification("Course", "2", EntityOperation.UPDATE);
            service.Dispose();

            // First call dequeues
            _controller.GetNotifications();

            // Second call should get empty queue
            var result2 = _controller.GetNotifications();
            var json2 = result2.Value;
            var countProp = json2.GetType().GetProperty("count");
            Assert.Equal(0, (int)countProp.GetValue(json2));
