using System.Collections.Generic;
using System.Linq;
using Xunit;

namespace ContosoUniversity.Tests
{
    public class PaginatedListTests
    {
        [Fact]
        public void Constructor_SetsProperties()
        {
            var items = new List<string> { "a", "b", "c" };
            var list = new PaginatedList<string>(items, 10, 2, 3);

            Assert.Equal(2, list.PageIndex);
            Assert.Equal(4, list.TotalPages); // ceil(10/3) = 4
            Assert.Equal(3, list.Count);
            Assert.Contains("a", list);
        }

        [Theory]
        [InlineData(1, false)]
        [InlineData(2, true)]
        [InlineData(3, true)]
        public void HasPreviousPage_ReturnsCorrectValue(int pageIndex, bool expected)
        {
            var list = new PaginatedList<int>(new List<int>(), 30, pageIndex, 10);
            Assert.Equal(expected, list.HasPreviousPage);
        }

        [Theory]
        [InlineData(1, 3, true)]  // page 1 of 3
        [InlineData(3, 3, false)] // page 3 of 3
        [InlineData(2, 3, true)]  // page 2 of 3
        public void HasNextPage_ReturnsCorrectValue(int pageIndex, int totalPages, bool expected)
        {
            // count = totalPages * pageSize
            var list = new PaginatedList<int>(new List<int>(), totalPages * 10, pageIndex, 10);
            Assert.Equal(expected, list.HasNextPage);
        }

        [Fact]
        public void TotalPages_CalculatesCorrectly()
        {
            // 25 items, page size 10 => 3 pages
            var list = new PaginatedList<int>(new List<int>(), 25, 1, 10);
            Assert.Equal(3, list.TotalPages);
        }

        [Fact]
        public void TotalPages_ExactDivision_CalculatesCorrectly()
        {
            // 20 items, page size 10 => 2 pages
            var list = new PaginatedList<int>(new List<int>(), 20, 1, 10);
            Assert.Equal(2, list.TotalPages);
        }

        [Fact]
        public void Create_ReturnsCorrectPage()
        {
            var source = Enumerable.Range(1, 50).AsQueryable();

            var result = PaginatedList<int>.Create(source, 2, 10);

            Assert.Equal(2, result.PageIndex);
            Assert.Equal(5, result.TotalPages);
            Assert.Equal(10, result.Count);
            Assert.Equal(11, result.First()); // 2nd page starts at 11
            Assert.Equal(20, result.Last());
        }

        [Fact]
        public void Create_FirstPage_HasCorrectItems()
        {
            var source = Enumerable.Range(1, 15).AsQueryable();

            var result = PaginatedList<int>.Create(source, 1, 5);

            Assert.Equal(1, result.PageIndex);
            Assert.Equal(3, result.TotalPages);
            Assert.True(result.HasNextPage);
            Assert.False(result.HasPreviousPage);
            Assert.Equal(new[] { 1, 2, 3, 4, 5 }, result.ToArray());
        }

        [Fact]
        public void Create_LastPage_HasRemainingItems()
        {
            var source = Enumerable.Range(1, 12).AsQueryable();

            var result = PaginatedList<int>.Create(source, 3, 5);

            Assert.Equal(3, result.TotalPages);
            Assert.False(result.HasNextPage);
            Assert.True(result.HasPreviousPage);
            Assert.Equal(new[] { 11, 12 }, result.ToArray());
        }

        [Fact]
        public void Create_EmptySource_ReturnsEmptyPage()
        {
            var source = Enumerable.Empty<int>().AsQueryable();

            var result = PaginatedList<int>.Create(source, 1, 10);

            Assert.Empty(result);
            Assert.Equal(0, result.TotalPages);
            Assert.False(result.HasPreviousPage);
            Assert.False(result.HasNextPage);
        }
    }
}

using ContosoUniversity.Models;
using ContosoUniversity.Services;
using ContosoUniversity.Tests.Helpers;
using Xunit;

namespace ContosoUniversity.Tests.Services
{
    public class NotificationServiceTests : IDisposable
    {
        private readonly NotificationService _service;

        public NotificationServiceTests()
        {
            NotificationQueueDrainer.Drain();
            _service = new NotificationService();
        }

        public void Dispose()
        {
            _service.Dispose();
            NotificationQueueDrainer.Drain();
        }

        [Fact]
        public void SendNotification_FourParamOverload_EnqueuesNotification()
        {
            _service.SendNotification("Student", "1", EntityOperation.CREATE);

            var notification = _service.ReceiveNotification();
            Assert.NotNull(notification);
            Assert.Equal("Student", notification.EntityType);
            Assert.Equal("1", notification.EntityId);
            Assert.Equal("CREATE", notification.Operation);
            Assert.Contains("Student (ID: 1)", notification.Message);
            Assert.Contains("created", notification.Message);
        }

        [Fact]
        public void SendNotification_FiveParamOverload_EnqueuesWithDisplayName()
        {
            _service.SendNotification("Course", "42", "Chemistry", EntityOperation.UPDATE, "admin");

            var notification = _service.ReceiveNotification();
            Assert.NotNull(notification);
            Assert.Equal("Course", notification.EntityType);
            Assert.Equal("42", notification.EntityId);
            Assert.Contains("Chemistry", notification.Message);
            Assert.Contains("updated", notification.Message);
            Assert.Equal("admin", notification.CreatedBy);
        }

        [Fact]
        public void SendNotification_WithNullUserName_DefaultsToSystem()
        {
            _service.SendNotification("Student", "1", EntityOperation.CREATE);

            var notification = _service.ReceiveNotification();
            Assert.Equal("System", notification.CreatedBy);
        }

        [Fact]
        public void SendNotification_SetsIsReadToFalse()
        {
            _service.SendNotification("Student", "1", EntityOperation.CREATE);

            var notification = _service.ReceiveNotification();
            Assert.False(notification.IsRead);
        }

        [Fact]
        public void ReceiveNotification_EmptyQueue_ReturnsNull()
        {
            var notification = _service.ReceiveNotification();
            Assert.Null(notification);
        }

        [Fact]
        public void ReceiveNotification_WithItems_DequeuesInOrder()
        {
            _service.SendNotification("A", "1", EntityOperation.CREATE);
            _service.SendNotification("B", "2", EntityOperation.UPDATE);

            var first = _service.ReceiveNotification();
            var second = _service.ReceiveNotification();

            Assert.Equal("A", first.EntityType);
            Assert.Equal("B", second.EntityType);
        }

        [Theory]
        [InlineData(EntityOperation.CREATE, "created")]
        [InlineData(EntityOperation.UPDATE, "updated")]
        [InlineData(EntityOperation.DELETE, "deleted")]
        public void GenerateMessage_WithoutDisplayName_ContainsOperationText(EntityOperation op, string expectedText)
        {
            _service.SendNotification("Student", "5", op);

            var notification = _service.ReceiveNotification();
            Assert.Contains(expectedText, notification.Message);
            Assert.Contains("Student (ID: 5)", notification.Message);
        }

        [Theory]
        [InlineData(EntityOperation.CREATE, "created")]
        [InlineData(EntityOperation.UPDATE, "updated")]
        [InlineData(EntityOperation.DELETE, "deleted")]
        public void GenerateMessage_WithDisplayName_UsesDisplayNameInMessage(EntityOperation op, string expectedText)
        {
            _service.SendNotification("Course", "101", "Calculus", op);

            var notification = _service.ReceiveNotification();
            Assert.Contains(expectedText, notification.Message);
            Assert.Contains("Course 'Calculus'", notification.Message);
        }

        [Fact]
        public void SendNotification_SetsCreatedAtToNow()
        {
            var before = DateTime.Now.AddSeconds(-1);
            _service.SendNotification("Student", "1", EntityOperation.CREATE);
            var after = DateTime.Now.AddSeconds(1);

            var notification = _service.ReceiveNotification();
            Assert.InRange(notification.CreatedAt, before, after);
        }

        [Fact]
        public void MarkAsRead_DoesNotThrow()
        {
            // MarkAsRead is a no-op, just verify it doesn't throw
            var ex = Record.Exception(() => _service.MarkAsRead(1));
            Assert.Null(ex);
        }

        [Fact]
        public void Dispose_DoesNotThrow()
        {
            var service = new NotificationService();
            var ex = Record.Exception(() => service.Dispose());
            Assert.Null(ex);
        }

        [Fact]
        public void QueueCap_EnforcesMaxLength()
        {
            // Send more than 500 notifications
            for (int i = 0; i < 510; i++)
            {
                _service.SendNotification("Test", i.ToString(), EntityOperation.CREATE);
            }

            // Drain the queue and count
            int count = 0;
            while (_service.ReceiveNotification() != null) count++;

            // Should be capped at 500
            Assert.True(count <= 500);
        }
    }
}

