        public CoursesControllerTests()
        {
            NotificationQueueDrainer.Drain();
            _context = TestDbContextFactory.Create();
            _mockEnv = new Mock<IWebHostEnvironment>();
            _mockLogger = new Mock<ILogger<CoursesController>>();

            // Use a temp directory for web root so file operations don't mess up real dirs
            _testWebRoot = Path.Combine(Path.GetTempPath(), "contoso_test_" + Guid.NewGuid().ToString("N"));
            Directory.CreateDirectory(_testWebRoot);
            _mockEnv.Setup(e => e.WebRootPath).Returns(_testWebRoot);
            _mockEnv.Setup(e => e.ContentRootPath).Returns(_testWebRoot);

            _controller = new CoursesController(_context, _mockEnv.Object, _mockLogger.Object);

            // Seed a department
            SeedDepartment();
        }

        public void Dispose()
        {
            _controller.Dispose();
