            var deptId = _context.Departments.First().DepartmentID;
            var course = new Course
            {
                CourseID = 7000,
                Title = "With Image",
                Credits = 3,
                DepartmentID = deptId,
                TeachingMaterialImagePath = "/Uploads/TeachingMaterials/" + fileName
            };
            _context.Courses.Add(course);
            _context.SaveChanges();

            _controller.DeleteConfirmed(7000);

            Assert.False(File.Exists(filePath));
        }

        [Theory]
        [InlineData(".jpg")]
        [InlineData(".jpeg")]
        [InlineData(".png")]
        [InlineData(".gif")]
        [InlineData(".bmp")]
        public void CreatePost_AllowedExtensions_AreAccepted(string extension)
        {
            var deptId = _context.Departments.First().DepartmentID;
            var courseId = 8000 + Math.Abs(extension.GetHashCode() % 1000);
            var course = new Course
            {
                CourseID = courseId,
                Title = $"Test {extension}",
                Credits = 3,
                DepartmentID = deptId
            };
            var mockFile = CreateMockFile($"image{extension}", 1024);

            var result = _controller.Create(course, mockFile.Object);

            Assert.IsType<RedirectToActionResult>(result);
        }
    }
}

