using System;
using System.Linq;
using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Services;
using ContosoUniversity.Tests.Helpers;
using Microsoft.AspNetCore.Mvc;
using Xunit;

namespace ContosoUniversity.Tests.Controllers
{
    public class NotificationsControllerTests : IDisposable
    {
        private readonly SchoolContext _context;
        private readonly NotificationsController _controller;

        public NotificationsControllerTests()
        {
            NotificationQueueDrainer.Drain();
            _context = TestDbContextFactory.Create();
            _controller = new NotificationsController(_context);
        }

        public void Dispose()
        {
            _controller.Dispose();
            _context.Dispose();
            NotificationQueueDrainer.Drain();
        }

        [Fact]
        public void GetNotifications_EmptyQueue_ReturnsEmptyList()
        {
            var result = _controller.GetNotifications();

            Assert.NotNull(result);
            var json = result.Value;
            Assert.NotNull(json);

            // Check count via dynamic or known property
            var successProp = json.GetType().GetProperty("success");
            Assert.True((bool)successProp.GetValue(json));

            var countProp = json.GetType().GetProperty("count");
            Assert.Equal(0, (int)countProp.GetValue(json));
        }

        [Fact]
        public void GetNotifications_WithNotifications_ReturnsUpTo10()
        {
            // Enqueue some notifications
            var service = new NotificationService();
            for (int i = 0; i < 15; i++)
            {
                service.SendNotification("Test", i.ToString(), EntityOperation.CREATE);
            }

            var result = _controller.GetNotifications();
            var json = result.Value;

            var countProp = json.GetType().GetProperty("count");
            Assert.Equal(10, (int)countProp.GetValue(json));

            service.Dispose();
        }

        [Fact]
        public void GetNotifications_DequeuesNotifications()
        {
            var service = new NotificationService();
            service.SendNotification("Student", "1", EntityOperation.CREATE);
            service.SendNotification("Course", "2", EntityOperation.UPDATE);
            service.Dispose();

            // First call dequeues
            _controller.GetNotifications();

            // Second call should get empty queue
            var result2 = _controller.GetNotifications();
            var json2 = result2.Value;
            var countProp = json2.GetType().GetProperty("count");
            Assert.Equal(0, (int)countProp.GetValue(json2));
        }

        [Fact]
        public void MarkAsRead_ReturnsSuccess()
        {
            var result = _controller.MarkAsRead(1);

            Assert.NotNull(result);
            var json = result.Value;
            var successProp = json.GetType().GetProperty("success");
            Assert.True((bool)successProp.GetValue(json));
        }

        [Fact]
        public void Index_ReturnsViewResult()
        {
            var result = _controller.Index();
            Assert.IsType<ViewResult>(result);
        }
    }
}

