+using System.Collections.Generic;
+using System.Linq;
+using Xunit;
+
+namespace ContosoUniversity.Tests
+{
+    public class PaginatedListTests
+    {
+        [Fact]
+        public void Constructor_SetsProperties()
+        {
+            var items = new List<string> { "a", "b", "c" };
+            var list = new PaginatedList<string>(items, 10, 2, 3);
+
+            Assert.Equal(2, list.PageIndex);
+            Assert.Equal(4, list.TotalPages); // ceil(10/3) = 4
+            Assert.Equal(3, list.Count);
+            Assert.Contains("a", list);
+        }
+
+        [Theory]
+        [InlineData(1, false)]
+        [InlineData(2, true)]
+        [InlineData(3, true)]
+        public void HasPreviousPage_ReturnsCorrectValue(int pageIndex, bool expected)
+        {
+            var list = new PaginatedList<int>(new List<int>(), 30, pageIndex, 10);
+            Assert.Equal(expected, list.HasPreviousPage);
+        }
+
+        [Theory]
+        [InlineData(1, 3, true)]  // page 1 of 3
+        [InlineData(3, 3, false)] // page 3 of 3
+        [InlineData(2, 3, true)]  // page 2 of 3
+        public void HasNextPage_ReturnsCorrectValue(int pageIndex, int totalPages, bool expected)
+        {
+            // count = totalPages * pageSize
+            var list = new PaginatedList<int>(new List<int>(), totalPages * 10, pageIndex, 10);
+            Assert.Equal(expected, list.HasNextPage);
+        }
+
+        [Fact]
+        public void TotalPages_CalculatesCorrectly()
+        {
+            // 25 items, page size 10 => 3 pages
+            var list = new PaginatedList<int>(new List<int>(), 25, 1, 10);
+            Assert.Equal(3, list.TotalPages);
+        }
+
+        [Fact]
+        public void TotalPages_ExactDivision_CalculatesCorrectly()
+        {
+            // 20 items, page size 10 => 2 pages
+            var list = new PaginatedList<int>(new List<int>(), 20, 1, 10);
+            Assert.Equal(2, list.TotalPages);
+        }
+
+        [Fact]
+        public void Create_ReturnsCorrectPage()
+        {
+            var source = Enumerable.Range(1, 50).AsQueryable();
+
+            var result = PaginatedList<int>.Create(source, 2, 10);
+
+            Assert.Equal(2, result.PageIndex);
+            Assert.Equal(5, result.TotalPages);
+            Assert.Equal(10, result.Count);
+            Assert.Equal(11, result.First()); // 2nd page starts at 11
+            Assert.Equal(20, result.Last());
+        }
+
+        [Fact]
+        public void Create_FirstPage_HasCorrectItems()
+        {
+            var source = Enumerable.Range(1, 15).AsQueryable();
+
+            var result = PaginatedList<int>.Create(source, 1, 5);
+
+            Assert.Equal(1, result.PageIndex);
+            Assert.Equal(3, result.TotalPages);
+            Assert.True(result.HasNextPage);
+            Assert.False(result.HasPreviousPage);
+            Assert.Equal(new[] { 1, 2, 3, 4, 5 }, result.ToArray());
+        }
+
+        [Fact]
+        public void Create_LastPage_HasRemainingItems()
+        {
+            var source = Enumerable.Range(1, 12).AsQueryable();
+
+            var result = PaginatedList<int>.Create(source, 3, 5);
+
+            Assert.Equal(3, result.TotalPages);
+            Assert.False(result.HasNextPage);
+            Assert.True(result.HasPreviousPage);
+            Assert.Equal(new[] { 11, 12 }, result.ToArray());
+        }
+
+        [Fact]
+        public void Create_EmptySource_ReturnsEmptyPage()
+        {
+            var source = Enumerable.Empty<int>().AsQueryable();
+
+            var result = PaginatedList<int>.Create(source, 1, 10);
+
+            Assert.Empty(result);
+            Assert.Equal(0, result.TotalPages);
+            Assert.False(result.HasPreviousPage);
+            Assert.False(result.HasNextPage);
+        }
+    }
+}
+

